Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <algorithm>

// Function to convert a string to lower case
std::string toLowerCase(const std::string& str) {
    std::string lowerStr = str;
    std::transform(lowerStr.begin(), lowerStr.end(), lowerStr.begin(), ::tolower);
    return lowerStr;
}

int main() {
    std::string filename;
    std::string word;

    // Prompt the user for the file name and the word to search
    std::cout << "Enter the name of the file: ";
    std::cin >> filename;
    std::cout << "Enter the word to count: ";
    std::cin >> word;

    // Convert the word to lower case
    word = toLowerCase(word);

    std::ifstream file(filename.c_str());
    if (!file.is_open()) {
        std::cerr << "Error: Could not open the file." << std::endl;
        return 1;
    }

    std::string line;
    int count = 0;
    // Read the file line by line
    while (std::getline(file, line)) {
        // Convert the line to lower case
        std::string lowerLine = toLowerCase(line);
        // Find the position of the word in the line
        size_t pos = lowerLine.find(word);
        // Check if the word is found in the line
        while (pos!= std::string::npos) {
            // Increment the count
            count++;
            // Find the next occurrence of the word
            pos = lowerLine.find(word, pos + word.length());
        }
    }

    file.close();
    // Output the result
    std::cout << "The word \"" << word << "\" occurs " << count << " times in the file." << std::endl;

    return 0;
}
```

To compile and run this program, save it to a file, for example `word_count.cpp`, and use the following commands:

```sh
g++ -o word_count word_count.cpp
./word_count
```

